import { GoogleGenAI, GenerateContentResponse, Type } from "@google/genai";
import type { ActionItem, Decision, TranscriptSegment, AnalysisResult } from "../types";

const API_KEY = process.env.API_KEY;

if (!API_KEY) {
  throw new Error("API_KEY is not defined. Please set the API_KEY environment variable.");
}

const ai = new GoogleGenAI({ apiKey: API_KEY });

type Language = 'vi' | 'en';

// Increased default retries and delay to handle RPC errors better
const withRetry = async <T>(fn: () => Promise<T>, retries = 5, delay = 2000): Promise<T> => {
  let lastError: any;
  for (let attempt = 1; attempt <= retries; attempt++) {
    try {
      return await fn();
    } catch (error) {
      lastError = error;
      const isNetworkError = error instanceof Error && (
        error.message.includes('Rpc failed') || 
        error.message.includes('fetch failed') ||
        error.message.includes('network')
      );

      // Only retry on network-like errors or 503s, or if it's a generic RPC failure
      if (attempt < retries) {
        console.warn(`API call failed on attempt ${attempt}. Retrying in ${delay * attempt}ms... Error: ${error instanceof Error ? error.message : String(error)}`);
        await new Promise((resolve) => setTimeout(resolve, delay * attempt));
      }
    }
  }
  throw lastError;
};


